// Centralized logging utility. Wraps console with consistent formatting and
// allows future integration with a remote sink (Sentry / App Insights) without
// touching call sites.

type LogLevel = 'debug' | 'info' | 'warn' | 'error';

const isDev = import.meta.env.DEV;

function emit(level: LogLevel, scope: string, message: string, ...args: unknown[]): void {
  // In production we still surface warn/error to the browser console so users
  // can include them in bug reports; debug/info are dev-only.
  if (!isDev && (level === 'debug' || level === 'info')) return;

  const prefix = `[${scope}]`;
  const fn =
    level === 'error' ? console.error
    : level === 'warn' ? console.warn
    : level === 'info' ? console.info
    : console.debug;

  fn(prefix, message, ...args);
}

export const logger = {
  debug: (scope: string, message: string, ...args: unknown[]) => emit('debug', scope, message, ...args),
  info: (scope: string, message: string, ...args: unknown[]) => emit('info', scope, message, ...args),
  warn: (scope: string, message: string, ...args: unknown[]) => emit('warn', scope, message, ...args),
  error: (scope: string, message: string, ...args: unknown[]) => emit('error', scope, message, ...args),
};

// Convenience for the most common case: a caught error.
export function logError(scope: string, message: string, error: unknown): void {
  emit('error', scope, message, error);
}
