export interface IEnvConfig {
    SiteName: string,
    SiteOwner: string,
    SiteTagline: string,
    SiteLogo: string,
    SiteVersion: string,
    ApiBasePath: string,
    PhotoBaseUrl: string,
    Socials: SiteConfigSocials,
}

// Branding from runtime config (public/site.config.js loaded via <script> in index.html)
import { getSiteConfig } from '@/utils/siteConfig';
const config = getSiteConfig();

// API base path from build-time env var (.env.local / .env.production)
const apiBasePath = import.meta.env.VITE_API_BASE_PATH || "https://alumniapp.azurewebsites.net";
const photoBaseUrl = import.meta.env.VITE_PHOTO_BASE_URL || "";
const siteVersion = import.meta.env.VITE_SITE_VERSION || "dev";

export const EnvConfig: IEnvConfig = {
    SiteName: config.siteName || "Untitled",
    SiteOwner: config.siteOwner || "Untitled",
    SiteTagline: config.siteTagline || "",
    SiteLogo: config.siteLogo || "",
    SiteVersion: siteVersion,
    ApiBasePath: apiBasePath,
    PhotoBaseUrl: photoBaseUrl,
    Socials: config.socials ?? {},
};